    if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {

    } else {
        // 총 조회건수 표시
        var rowCnt = ds_dailySalary.getRowCount();
        txt_totalRows.setValue(rowCnt);

        if (rowCnt == 0) {			
            $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
        } 			
